body.script:
        // ============================================
        // TMDB API MODULE
        // ============================================
        const TMDB = {
            API_KEY: 'e10da2e2cbb23ea7ebfb64c3a188b64a',
            BASE_URL: 'https://api.themoviedb.org/3',
            IMG_BASE: 'https://image.tmdb.org/t/p',

            async fetchData(endpoint) {
                const url = `${this.BASE_URL}${endpoint}${endpoint.includes('?') ? '&' : '?'}api_key=${this.API_KEY}`;
                const res = await fetch(url);
                if (!res.ok) throw new Error(`TMDB API error: ${res.status}`);
                return res.json();
            },

            trending() { return this.fetchData('/trending/all/day'); },
            popularMovies(page = 1) { return this.fetchData(`/movie/popular?page=${page}`); },
            popularTV(page = 1) { return this.fetchData(`/tv/popular?page=${page}`); },
            topRatedMovies(page = 1) { return this.fetchData(`/movie/top_rated?page=${page}`); },
            upcomingMovies(page = 1) { return this.fetchData(`/movie/upcoming?page=${page}`); },
            airingToday(page = 1) { return this.fetchData(`/tv/airing_today?page=${page}`); },
            movieDetails(id) { return this.fetchData(`/movie/${id}?append_to_response=videos,credits,recommendations`); },
            tvDetails(id) { return this.fetchData(`/tv/${id}?append_to_response=videos,credits,recommendations`); },
            tvSeason(id, seasonNum) { return this.fetchData(`/tv/${id}/season/${seasonNum}`); },
            searchMulti(query, page = 1) { return this.fetchData(
                    `/search/multi?query=${encodeURIComponent(query)}&page=${page}`); },
            imageUrl(path, size = 'w500') {
                if (!path) return 'data:image/svg+xml,🎬';
                return `${this.IMG_BASE}/${size}${path}`;
            },
            originalImage(path) { return this.imageUrl(path, 'original'); },
            backdropUrl(path) { return this.imageUrl(path, 'w1280'); },
        };

        // ============================================
        // PLAYER MODULE - Stream URL Generator
        // ============================================
        const Player = {
            servers: {
                vidstorm: { name: 'VidStorm', color: '#8b5cf6' },
                vidrock: { name: 'VidRock', color: '#d946ef' },
                vidplus: { name: 'VidPlus', color: '#f59e0b' },
            },

            generateMovieEmbed(tmdbId, server) {
                const urls = {
                    vidstorm: `https://vidstorm.ru/movie/${tmdbId}`,
                    vidrock: `https://vidrock.ru/movie/${tmdbId}`,
                    vidplus: `https://player.vidplus.to/embed/movie/${tmdbId}`,
                };
                return urls[server] || urls['vidplus'];
            },

            generateTVEmbed(tmdbId, season, episode, server) {
                const urls = {
                    vidstorm: `https://vidstorm.ru/tv/${tmdbId}/${season}/${episode}`,
                    vidrock: `https://vidrock.ru/tv/${tmdbId}/${season}/${episode}`,
                    vidplus: `https://player.vidplus.to/embed/tv/${tmdbId}/${season}/${episode}`,
                };
                return urls[server] || urls['vidplus'];
            },

            getDefaultServer() {
                return localStorage.getItem('preferred_server') || 'vidplus';
            },

            setDefaultServer(server) {
                localStorage.setItem('preferred_server', server);
            },
        };

        // ============================================
        // STORAGE MODULE
        // ============================================
        const Storage = {
            get(key, defaultValue = null) {
                try {
                    const val = localStorage.getItem(key);
                    return val ? JSON.parse(val) : defaultValue;
                } catch { return defaultValue; }
            },
            set(key, value) {
                try { localStorage.setItem(key, JSON.stringify(value)); } catch {}
            },

            getContinueWatching() { return this.get('continueWatching', []); },
            addContinueWatching(item) {
                let list = this.getContinueWatching();
                list = list.filter(i => !(i.id === item.id && i.type === item.type));
                list.unshift({ ...item, timestamp: Date.now() });
                if (list.length > 30) list = list.slice(0, 30);
                this.set('continueWatching', list);
            },
            getWatchHistory() { return this.get('watchHistory', []); },
            addWatchHistory(item) {
                let list = this.getWatchHistory();
                list = list.filter(i => !(i.id === item.id && i.type === item.type && i.season === item
                    .season && i.episode === item.episode));
                list.unshift({ ...item, watchedAt: Date.now() });
                if (list.length > 50) list = list.slice(0, 50);
                this.set('watchHistory', list);
            },
        };

        // ============================================
        // UI HELPERS
        // ============================================
        const UI = {
            mainContent: document.getElementById('mainContent'),
            toastContainer: document.getElementById('toastContainer'),
            searchInput: document.getElementById('searchInput'),
            searchDropdown: document.getElementById('searchDropdown'),
            mobileNav: document.getElementById('mobileNav'),
            headerSearch: document.getElementById('headerSearch'),

            showToast(message, duration = 3000) {
                const toast = document.createElement('div');
                toast.className = 'toast';
                toast.textContent = message;
                this.toastContainer.appendChild(toast);
                setTimeout(() => { toast.style.opacity = '0';
                    toast.style.transition = 'opacity 0.3s';
                    setTimeout(() => toast.remove(), 300); }, duration);
            },

            showSkeleton(count = 12) {
                let html = '
';
                for (let i = 0; i < count; i++) {
                    html += '
';
                }
                html += '';
                return html;
            },

            renderCardGrid(items, linkType = 'movie') {
                if (!items || items.length === 0) return '
No results found.';
                let html = '
';
                items.forEach(item => {
                    const isMovie = item.media_type === 'movie' || linkType === 'movie';
                    const actualType = item.media_type || linkType;
                    const id = item.id;
                    const title = item.title || item.name || 'Untitled';
                    const poster = TMDB.imageUrl(item.poster_path);
                    const rating = item.vote_average ? item.vote_average.toFixed(1) : 'N/A';
                    const year = (item.release_date || item.first_air_date || '').substring(0, 4);
                    const detailPage = actualType === 'tv' ? 'show' : 'movie';
                    html += `


                  <img class="card-poster" src="${poster}" alt="${title}" loading="lazy" onerror="this.src='data:image/svg+xml,🎬'">

⭐ ${rating}



${title}

${year} • ${actualType === 'tv' ? 'TV' : 'Movie'}

                `;
                });
                html += '';
                return html;
            },

            renderCastGrid(cast) {
                if (!cast || cast.length === 0) return '
No cast info available.';
                let html = '
';
                cast.slice(0, 20).forEach(person => {
                    const avatar = TMDB.imageUrl(person.profile_path, 'w185');
                    html += `


                  <img class="cast-avatar" src="${avatar}" alt="${person.name}" loading="lazy" onerror="this.src='data:image/svg+xml,👤'">

${person.name}

${person.character || person.roles?.[0]?.character || ''}
                `;
                });
                html += '';
                return html;
            },

            renderEpisodeList(episodes) {
                if (!episodes || episodes.length === 0)
                return '
No episodes found.';
                let html = '
';
                episodes.forEach(ep => {
                    const still = TMDB.imageUrl(ep.still_path, 'w300');
                    html += `






S${ep.season_number} E${ep.episode_number}

${ep.name}

${ep.runtime || '?'} min • ${ep.air_date || 'TBA'}

                `;
                });
                html += '';
                return html;
            },
        };

        // ============================================
        // ROUTER
        // ============================================
        const router = {
            currentPage: null,
            currentParams: {},

            navigate(path) {
                if (path.startsWith('/')) {
                    // Parse the path
                    const [base, queryString] = path.split('?');
                    const params = {};
                    if (queryString) {
                        queryString.split('&').forEach(p => {
                            const [k, v] = p.split('=');
                            params[decodeURIComponent(k)] = decodeURIComponent(v || '');
                        });
                    }
                    this.currentParams = params;

                    // Update URL hash
                    window.location.hash = path;

                    // Render page
                    this.renderPage(base, params);
                }
                UI.mobileNav.classList.remove('open');
            },

            getCurrentRoute() {
                const hash = window.location.hash.replace('#', '') || '/';
                const [base, queryString] = hash.split('?');
                const params = {};
                if (queryString) {
                    queryString.split('&').forEach(p => {
                        const [k, v] = p.split('=');
                        params[decodeURIComponent(k)] = decodeURIComponent(v || '');
                    });
                }
                return { base, params };
            },

            async renderPage(base, params) {
                UI.mainContent.innerHTML = UI.showSkeleton(8);
                window.scrollTo({ top: 0, behavior: 'smooth' });
                this.currentPage = base;

                try {
                    switch (base) {
                        case '/':
                            await this.renderHome();
                            break;
                        case '/movie':
                            await this.renderMovieDetail(params);
                            break;
                        case '/show':
                            await this.renderTVDetail(params);
                            break;
                        case '/watch':
                            await this.renderWatch(params);
                            break;
                        case '/search':
                            await this.renderSearch(params);
                            break;
                        case '/trending':
                            await this.renderTrending();
                            break;
                        case '/movies':
                            await this.renderMoviesPage();
                            break;
                        case '/tv':
                            await this.renderTVPage();
                            break;
                        case '/schedule':
                            await this.renderSchedule();
                            break;
                        default:
                            await this.renderHome();
                    }
                } catch (err) {
                    console.error('Router error:', err);
                    UI.mainContent.innerHTML =
                        '

Something went wrong
Please try again later.Go Home';
                }

                // Update active nav link
                document.querySelectorAll('.nav-link').forEach(el => el.classList.remove('active'));
                const activeLink = document.querySelector(`.nav-link[data-route="${base}"]`);
                if (activeLink) activeLink.classList.add('active');
            },

            async renderHome() {
                let html = '';

                // Hero Section
                try {
                    const trending = await TMDB.trending();
                    const heroItem = trending.results?.find(r => r.backdrop_path && (r.media_type === 'movie' || r
                        .media_type === 'tv')) || trending.results?.[0];
                    if (heroItem) {
                        const heroType = heroItem.media_type === 'tv' ? 'show' : 'movie';
                        const heroTitle = heroItem.title || heroItem.name;
                        html += `









${heroTitle}


                        ⭐ ${heroItem.vote_average?.toFixed(1) || 'N/A'}
                        ${(heroItem.release_date || heroItem.first_air_date || '').substring(0,4)}
                        ${heroItem.media_type === 'tv' ? 'TV Series' : 'Movie'}


${heroItem.overview || 'No description available.'}


                        ▶ Watch Now
                        ℹ More Info


                  `;
                    }
                } catch (e) { console.error('Hero error:', e); }

                // Trending Section
                html += '


🔥 Trending NowSee All →';
                try {
                    const trending = await TMDB.trending();
                    html += UI.renderCardGrid(trending.results?.slice(0, 12) || []);
                } catch (e) { html += '
Failed to load trending.'; }
                html += '';

                // Continue Watching
                const continueList = Storage.getContinueWatching();
                if (continueList.length > 0) {
                    html +=
                        '


📌 Continue Watching';
                    html += '
';
                    continueList.slice(0, 8).forEach(item => {
                        const poster = TMDB.imageUrl(item.poster);
                        const detailPage = item.type === 'tv' ? 'show' : 'movie';
                        html += `


                    <img class="card-poster" src="${poster}" alt="${item.title}" loading="lazy" onerror="this.src='data:image/svg+xml,🎬'">



${item.title}

${item.type==='tv'?'S'+item.season+' E'+item.episode:''} • Continue

                  `;
                    });
                    html += '';
                }

                // Popular Movies
                html +=
                '


🎬 Popular MoviesSee All →';
                try {
                    const popMovies = await TMDB.popularMovies();
                    html += UI.renderCardGrid(popMovies.results?.slice(0, 12) || [], 'movie');
                } catch (e) { html += '
Failed to load movies.'; }
                html += '';

                // Popular TV
                html +=
                '


📺 Popular TV ShowsSee All →';
                try {
                    const popTV = await TMDB.popularTV();
                    html += UI.renderCardGrid(popTV.results?.slice(0, 12) || [], 'tv');
                } catch (e) { html += '
Failed to load TV shows.'; }
                html += '';

                // Upcoming
                html +=
                '


📅 Upcoming MoviesSee All →';
                try {
                    const upcoming = await TMDB.upcomingMovies();
                    html += UI.renderCardGrid(upcoming.results?.slice(0, 12) || [], 'movie');
                } catch (e) { html += '
Failed to load upcoming.'; }
                html += '';

                UI.mainContent.innerHTML = html;
            },

            async renderMovieDetail(params) {
                const id = params.id;
                if (!id) { router.navigate('/'); return; }
                const data = await TMDB.movieDetails(id);
                const trailer = data.videos?.results?.find(v => v.type === 'Trailer' && v.site === 'YouTube');
                let html = `












${data.title}
                    ${data.tagline ? `
"${data.tagline}"` : ''}

${(data.genres||[]).map(g=>`${g.name}`).join('')}


                      ⭐ ${data.vote_average?.toFixed(1)}
                      ⏱ ${data.runtime} min
                      📅 ${data.release_date}
                      ${data.production_companies?.slice(0,2).map(c=>`🏢 ${c.name}`).join('')}


${data.overview || 'No description.'}


                      ▶ Watch Movie
                      ${trailer ? `🎬 Trailer` : ''}



              `;

                // Cast
                html += '


👥 Cast';
                html += UI.renderCastGrid(data.credits?.cast);
                html += '';

                // Recommendations
                if (data.recommendations?.results?.length > 0) {
                    html +=
                    '


🎯 Recommendations';
                    html += UI.renderCardGrid(data.recommendations.results.slice(0, 12), 'movie');
                    html += '';
                }

                UI.mainContent.innerHTML = html;
                document.title = `${data.title} - CineStream`;
            },

            async renderTVDetail(params) {
                const id = params.id;
                if (!id) { router.navigate('/'); return; }
                const data = await TMDB.tvDetails(id);
                const trailer = data.videos?.results?.find(v => v.type === 'Trailer' && v.site === 'YouTube');
                let html = `












${data.name}
                    ${data.tagline ? `
"${data.tagline}"` : ''}

${(data.genres||[]).map(g=>`${g.name}`).join('')}


                      ⭐ ${data.vote_average?.toFixed(1)}
                      📺 ${data.number_of_seasons} Seasons
                      📅 ${data.first_air_date}
                      ${data.networks?.slice(0,2).map(n=>`🏢 ${n.name}`).join('')}


${data.overview || 'No description.'}


                      ▶ Watch S1 E1
                      ${trailer ? `🎬 Trailer` : ''}



              `;

                // Seasons
                html +=
                    '


📂 Seasons';
                for (let s = 1; s <= (data.number_of_seasons || 1); s++) {
                    html += `Season ${s}`;
                }
                html += '
';
                try {
                    const s1 = await TMDB.tvSeason(id, 1);
                    html += UI.renderEpisodeList(s1.episodes || []);
                } catch (e) { html += '
Could not load episodes.'; }
                html += '';

                // Cast
                html += '


👥 Cast';
                html += UI.renderCastGrid(data.credits?.cast);
                html += '';

                // Recommendations
                if (data.recommendations?.results?.length > 0) {
                    html +=
                    '


🎯 Recommendations';
                    html += UI.renderCardGrid(data.recommendations.results.slice(0, 12), 'tv');
                    html += '';
                }

                UI.mainContent.innerHTML = html;
                document.title = `${data.name} - CineStream`;
                window._currentTVId = id;
            },

            async renderWatch(params) {
                const id = params.id;
                const type = params.type || 'movie';
                const season = params.season || '1';
                const episode = params.episode || '1';
                const server = params.server || Player.getDefaultServer();

                if (!id) { router.navigate('/'); return; }

                let embedSrc;
                let title = '';
                let posterPath = '';

                if (type === 'movie') {
                    embedSrc = Player.generateMovieEmbed(id, server);
                    try {
                        const data = await TMDB.movieDetails(id);
                        title = data.title;
                        posterPath = data.poster_path;
                        Storage.addContinueWatching({ id, type, title, poster: posterPath, season: 1, episode: 1 });
                        Storage.addWatchHistory({ id, type, title, poster: posterPath, season: 1, episode: 1 });
                        document.title = `Watching: ${title} - CineStream`;
                    } catch (e) { title = 'Movie'; }
                } else {
                    embedSrc = Player.generateTVEmbed(id, season, episode, server);
                    try {
                        const data = await TMDB.tvDetails(id);
                        title = data.name;
                        posterPath = data.poster_path;
                        Storage.addContinueWatching({ id, type, title, poster: posterPath, season: parseInt(season),
                            episode: parseInt(episode) });
                        Storage.addWatchHistory({ id, type, title, poster: posterPath, season: parseInt(season),
                            episode: parseInt(episode) });
                        document.title = `Watching: ${title} S${season}E${episode} - CineStream`;
                    } catch (e) { title = 'TV Show'; }
                }

                let html = `



${title} ${type==='tv'?`- S${season} E${episode}`:''}







                Server:`;
                Object.entries(Player.servers).forEach(([key, val]) => {
                    html +=
                        `${val.name}`;
                });
                html += '';

                // Episode navigation for TV
                if (type === 'tv') {
                    html += '
';
                    const epNum = parseInt(episode);
                    if (epNum > 1) {
                        html +=
                            `⬅ Prev Episode`;
                    }
                    html +=
                        `Next Episode ➡`;
                    html += '';
                    // Load episode list
                    try {
                        const seasonData = await TMDB.tvSeason(id, season);
                        html +=
                            '


Episodes';
                        html += UI.renderEpisodeList(seasonData.episodes || []);
                        html += '';
                    } catch (e) {}
                }

                UI.mainContent.innerHTML = html;
                window._watchParams = { id, type, season, episode, server };
            },

            async renderSearch(params) {
                const query = params.q || '';
                document.title = `Search: ${query} - CineStream`;
                UI.searchInput.value = query;
                let html =
                    `


🔍 Results for "${query}"`;
                if (query) {
                    try {
                        const results = await TMDB.searchMulti(query);
                        const filtered = (results.results || []).filter(r => r.media_type === 'movie' || r
                            .media_type === 'tv');
                        html += UI.renderCardGrid(filtered);
                    } catch (e) { html += '
Search failed. Try again.'; }
                } else {
                    html += '
Enter a search term to find movies and TV shows.';
                }
                html += '';
                UI.mainContent.innerHTML = html;
            },

            async renderTrending() {
                document.title = 'Trending - CineStream';
                let html =
                    '


🔥 Trending Now';
                try {
                    const data = await TMDB.trending();
                    html += UI.renderCardGrid(data.results || []);
                } catch (e) { html += '
Failed to load.'; }
                html += '';
                UI.mainContent.innerHTML = html;
            },

            async renderMoviesPage() {
                document.title = 'Popular Movies - CineStream';
                let html =
                    '


🎬 Popular Movies';
                try {
                    const data = await TMDB.popularMovies();
                    html += UI.renderCardGrid(data.results || [], 'movie');
                } catch (e) { html += '
Failed to load.'; }
                html += '';
                UI.mainContent.innerHTML = html;
            },

            async renderTVPage() {
                document.title = 'Popular TV Shows - CineStream';
                let html =
                    '


📺 Popular TV Shows';
                try {
                    const data = await TMDB.popularTV();
                    html += UI.renderCardGrid(data.results || [], 'tv');
                } catch (e) { html += '
Failed to load.'; }
                html += '';
                UI.mainContent.innerHTML = html;
            },

            async renderSchedule() {
                document.title = 'Schedule - CineStream';
                let html = '';
                html +=
                '


📅 Upcoming Movies';
                try {
                    const upcoming = await TMDB.upcomingMovies();
                    html += UI.renderCardGrid(upcoming.results || [], 'movie');
                } catch (e) { html += '
Failed to load.'; }
                html += '';
                html +=
                '


📺 Airing Today';
                try {
                    const airing = await TMDB.airingToday();
                    html += UI.renderCardGrid(airing.results || [], 'tv');
                } catch (e) { html += '
Failed to load.'; }
                html += '';
                UI.mainContent.innerHTML = html;
            },
        };

        // ============================================
        // GLOBAL FUNCTIONS
        // ============================================
        function switchServer(id, type, season, episode, server) {
            Player.setDefaultServer(server);
            router.navigate(`/watch?id=${id}&type=${type}&season=${season}&episode=${episode}&server=${server}`);
        }

        function playEpisode(seasonNum, episodeNum) {
            const tvId = window._currentTVId || window._watchParams?.id;
            if (tvId) {
                router.navigate(
                    `/watch?id=${tvId}&type=tv&season=${seasonNum}&episode=${episodeNum}&server=${Player.getDefaultServer()}`
                    );
            }
        }

        async function loadSeasonEpisodes(tvId, seasonNum) {
            const container = document.getElementById('episodesContainer');
            if (!container) return;
            container.innerHTML = '
Loading episodes...';
            try {
                const data = await TMDB.tvSeason(tvId, seasonNum);
                container.innerHTML = UI.renderEpisodeList(data.episodes || []);
                // Update onclick handlers
                container.querySelectorAll('.episode-card').forEach(card => {
                    const epNum = card.getAttribute('data-ep') || card.querySelector('.episode-num')
                        ?.textContent?.match(/E(\d+)/)?.[1];
                    if (epNum) {
                        card.onclick = () => playEpisode(seasonNum, parseInt(epNum));
                    }
                });
                // Re-bind episode cards
                container.querySelectorAll('.episode-card').forEach((card, i) => {
                    const ep = data.episodes?.[i];
                    if (ep) {
                        card.onclick = () => playEpisode(seasonNum, ep.episode_number);
                    }
                });
            } catch (e) {
                container.innerHTML = '
Failed to load episodes.';
            }
        }

        function closeMobileNav() {
            UI.mobileNav.classList.remove('open');
        }

        // ============================================
        // SEARCH DEBOUNCE
        // ============================================
        let searchTimeout;
        UI.searchInput.addEventListener('input', function() {
            clearTimeout(searchTimeout);
            const query = this.value.trim();
            if (query.length < 2) {
                UI.searchDropdown.classList.remove('active');
                return;
            }
            searchTimeout = setTimeout(async () => {
                try {
                    const data = await TMDB.searchMulti(query);
                    const filtered = (data.results || []).filter(r => r.media_type === 'movie' || r
                        .media_type === 'tv').slice(0, 8);
                    if (filtered.length > 0) {
                        let dropHtml = '';
                        filtered.forEach(item => {
                            const poster = TMDB.imageUrl(item.poster_path, 'w92');
                            const detailPage = item.media_type === 'tv' ? 'show' : 'movie';
                            dropHtml += `






${item.title||item.name}

${item.media_type==='tv'?'TV Show':'Movie'} • ${(item.release_date||item.first_air_date||'').substring(0,4)}

                        `;
                        });
                        UI.searchDropdown.innerHTML = dropHtml;
                        UI.searchDropdown.classList.add('active');
                    } else {
                        UI.searchDropdown.innerHTML =
                            '
No results found.';
                        UI.searchDropdown.classList.add('active');
                    }
                } catch (e) { /* silent */ }
            }, 350);
        });

        UI.searchInput.addEventListener('keydown', function(e) {
            if (e.key === 'Enter') {
                const query = this.value.trim();
                if (query) {
                    router.navigate(`/search?q=${encodeURIComponent(query)}`);
                    UI.searchDropdown.classList.remove('active');
                    this.blur();
                }
            }
        });

        document.getElementById('searchBtn').addEventListener('click', () => {
            const query = UI.searchInput.value.trim();
            if (query) {
                router.navigate(`/search?q=${encodeURIComponent(query)}`);
                UI.searchDropdown.classList.remove('active');
            }
        });

        // Close search dropdown on outside click
        document.addEventListener('click', (e) => {
            if (!UI.searchDropdown.contains(e.target) && e.target !== UI.searchInput) {
                UI.searchDropdown.classList.remove('active');
            }
        });

        // ============================================
        // MOBILE MENU & SEARCH TOGGLE
        // ============================================
        document.getElementById('menuBtn').addEventListener('click', () => {
            UI.mobileNav.classList.toggle('open');
        });

        const mobileSearchToggle = document.getElementById('mobileSearchToggle');
        if (window.innerWidth <= 768) {
            mobileSearchToggle.style.display = 'block';
        }
        mobileSearchToggle.addEventListener('click', () => {
            UI.headerSearch.classList.toggle('mobile-search-active');
            if (UI.headerSearch.classList.contains('mobile-search-active')) {
                UI.searchInput.focus();
            }
        });

        window.addEventListener('resize', () => {
            if (window.innerWidth <= 768) {
                mobileSearchToggle.style.display = 'block';
            } else {
                mobileSearchToggle.style.display = 'none';
                UI.headerSearch.classList.remove('mobile-search-active');
            }
        });

        // ============================================
        // PARTICLES CANVAS
        // ============================================
        (function() {
            const canvas = document.getElementById('particles-canvas');
            const ctx = canvas.getContext('2d');
            let particles = [];
            const maxParticles = 50;

            function resize() {
                canvas.width = window.innerWidth;
                canvas.height = window.innerHeight;
            }
            resize();
            window.addEventListener('resize', resize);

            class Particle {
                constructor() {
                    this.reset();
                }
                reset() {
                    this.x = Math.random() * canvas.width;
                    this.y = Math.random() * canvas.height;
                    this.size = Math.random() * 2 + 0.5;
                    this.speedX = (Math.random() - 0.5) * 0.3;
                    this.speedY = (Math.random() - 0.5) * 0.3;
                    this.opacity = Math.random() * 0.4 + 0.1;
                }
                update() {
                    this.x += this.speedX;
                    this.y += this.speedY;
                    if (this.x < 0 || this.x > canvas.width || this.y < 0 || this.y > canvas.height) {
                        this.reset();
                    }
                }
                draw() {
                    ctx.beginPath();
                    ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
                    ctx.fillStyle = `rgba(139,92,246,${this.opacity})`;
                    ctx.fill();
                }
            }

            for (let i = 0; i < maxParticles; i++) {
                particles.push(new Particle());
            }

            function animate() {
                ctx.clearRect(0, 0, canvas.width, canvas.height);
                particles.forEach(p => { p.update();
                    p.draw(); });
                requestAnimationFrame(animate);
            }
            animate();
        })();

        // ============================================
        // INITIALIZATION
        // ============================================
        function init() {
            const { base, params } = router.getCurrentRoute();
            router.renderPage(base, params);
        }

        // Handle hash changes
        window.addEventListener('hashchange', init);

        // Handle initial load
        if (window.location.hash) {
            init();
        } else {
            window.location.hash = '/';
            init();
        }

        // Keyboard shortcuts
        document.addEventListener('keydown', (e) => {
            if (e.key === 'f' && !e.target.closest('input')) {
                e.preventDefault();
                if (document.getElementById('video-player')) {
                    const iframe = document.getElementById('video-player');
                    if (iframe.requestFullscreen) iframe.requestFullscreen();
                }
            }
            if (e.key === 't' && !e.target.closest('input')) {
                e.preventDefault();
                const iframe = document.getElementById('video-player');
                if (iframe) {
                    iframe.style.position = 'fixed';
                    iframe.style.top = '0';
                    iframe.style.left = '0';
                    iframe.style.width = '100vw';
                    iframe.style.height = '100vh';
                    iframe.style.zIndex = '9999';
                    iframe.style.borderRadius = '0';
                }
            }
            if (e.key === 'Escape') {
                const iframe = document.getElementById('video-player');
                if (iframe && iframe.style.position === 'fixed') {
                    iframe.style.position = '';
                    iframe.style.top = '';
                    iframe.style.left = '';
                    iframe.style.width = '';
                    iframe.style.height = '';
                    iframe.style.zIndex = '';
                    iframe.style.borderRadius = '';
                }
            }
        });

        console.log('🎬 CineStream Platform Initialized');
        console.log('   TMDB API Integrated | Multi-Server Streaming | Cinematic UI');
        console.log('   Pages: Home | Movie | TV Show | Watch | Search | Trending');
        console.log('   Servers: VidStorm | VidRock | VidPlus');

if ('serviceWorker' in navigator) {
    window.addEventListener('load', () => {
        navigator.serviceWorker.register('/sw.js').then(reg => {
            console.log('SW registered:', reg.scope);
        }).catch(err => {
            console.log('SW registration failed:', err);
        });
    });
}
